4	function hasValidOperatorToken(candidate: string | null | undefined): boolean {
5	  const expected = process.env.OMEGA_OPERATOR_TOKEN?.trim();
6	  return Boolean(expected) && Boolean(candidate) && candidate === expected;
7	}
