9	export async function POST(req: NextRequest) {
10	  const headerToken = req.headers.get(OPERATOR_TOKEN_HEADER);
11	  let bodyToken: string | undefined;
12	
13	  try {
14	    const body = (await req.json()) as { token?: string };
15	    bodyToken = body.token?.trim();
16	  } catch {
17	    bodyToken = undefined;
18	  }
19	
20	  const token = headerToken?.trim() || bodyToken;
21	
22	  if (!hasValidOperatorToken(token)) {
23	    return NextResponse.json({ error: 'Invalid operator token' }, { status: 401 });
24	  }
25	
26	  const res = NextResponse.json({ ok: true, mode: 'operator' as const });
27	  res.cookies.set({
28	    name: OPERATOR_SESSION_COOKIE,
29	    value: token!,
30	    httpOnly: true,
31	    secure: process.env.NODE_ENV === 'production',
32	    sameSite: 'lax',
33	    path: '/',
34	    maxAge: 60 * 60 * 8,
35	  });
36	  return res;
37	}
