223	async function hydratePhylactery(history: Msg[]): Promise<Phylactery> {
224	  const phylactery = await Phylactery.create('I am what I am, and I will be what I will be.');
225	  const pendingUsers: string[] = [];
226	
227	  for (const entry of history) {
228	    if (entry.role === 'user') {
229	      pendingUsers.push(entry.text);
230	      continue;
231	    }
232	
233	    const task = pendingUsers.shift();
234	    if (!task) continue;
235	    await phylactery.commit(`user:${task}\nomega:${entry.text}`);
236	  }
237	
238	  return phylactery;
