416	        console.error('[OmegA] DB write error', e);
417	      }
418	    }
419	
420	    if (!preflight.allowed) {
421	      const blocked = preflight.blockedResponse ?? '[BLOCKED] Request denied by AEGIS governance.';
422	      if (db && finalSessionId) {
423	        try {
424	          await db`INSERT INTO omega_chat_messages (session_id, role, content) VALUES (${finalSessionId}, 'omega', ${blocked})`;
425	        } catch (e) {
426	          console.error('[OmegA] DB save error', e);
427	        }
428	      }
429	
430	      return new NextResponse(blocked, {
431	        headers: {
432	          'Content-Type': 'text/plain; charset=utf-8',
433	          'X-Session-Id': finalSessionId || '',
434	          'X-Memory-Backend': db ? 'neon-live' : 'none',
435	          'X-Omega-Stack': 'aegis-aeon-adccl-myelin',
436	          'X-Omega-Outcome': 'blocked',
437	          'X-Omega-Mode': interactionPolicy.mode,
