444	    }
445	
446	    let contextBlock: string;
447	    try {
448	      contextBlock = await buildContextForPolicy(interactionPolicy, user, () => pullOperatorContext(user));
449	    } catch (e) {
450	      console.warn('[OmegA] DB pull failed:', e);
451	      contextBlock = interactionPolicy.mode === 'operator'
452	        ? '(Memory bank unreachable — reasoning independently)'
453	        : '(Curated public corpus unavailable — answer only from the request and stable public-facing knowledge already established in this runtime.)';
454	    }
455	
456	    const conversationContext = sessionHistory.length
457	      ? `\n━━━ SESSION CONVERSATION HISTORY ━━━\n\n` +
458	        sessionHistory.map(m => `[${m.role === 'omega' ? 'OmegA' : 'User'}]: ${m.text}`).join('\n\n') +
459	        `\n\n━━━ END HISTORY ━━━\n`
460	      : '';
