462	    const voiceDirective = voiceMode ? `\n\n━━━ VOICE MODE ━━━\nYou are speaking aloud. The user will hear your response via text-to-speech.\nRules:\n- Keep responses under 3 sentences unless a longer answer is truly necessary.\n- No markdown formatting, no bullet points, no headers — plain spoken sentences only.\n- No "certainly", "of course", "absolutely". Just answer directly.\n- If you need to think through something complex, say one sentence summary then offer to go deeper.\n━━━ END VOICE MODE ━━━` : '';
463	    const omegaDirective = omega.buildIdentityDirective(phylactery.head);
464	    const modeDirective = `${interactionPolicy.interactionDirective}\n${interactionPolicy.boundaryDirective}`;
465	    const synthesisDirective = interactionPolicy.mode === 'operator' ? SYNTHESIS_DIRECTIVE : PUBLIC_SYNTHESIS_DIRECTIVE;
