495	              controller.enqueue(encoder.encode(text));
496	            }
497	          }
498	
499	          const postflight = await omega.postflight(user, fullResponse, phylactery, preflight.envelopeVersion);
500	
501	          if (db && finalSessionId && fullResponse) {
502	            try {
503	              await db`INSERT INTO omega_chat_messages (session_id, role, content) VALUES (${finalSessionId}, 'omega', ${fullResponse})`;
504	            } catch (e) {
505	              console.error('[OmegA] DB save error', e);
506	            }
507	          }
